import{_ as t,a,b as n,c as i}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as l,o,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Google-Drive-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/google-drive.md","filePath":"de-DE/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"de-DE/upload/google-drive.md"};function c(h,e,u,p,g,b){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="google-drive-kanal-hinzufugen" tabindex="-1">Google-Drive-Kanal hinzufügen <a class="header-anchor" href="#google-drive-kanal-hinzufugen" aria-label="Permalink to &quot;Google-Drive-Kanal hinzufügen&quot;">​</a></h1><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><p>Bereite vor dem Start diese Dinge vor:</p><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Wofür sie gebraucht wird</th></tr></thead><tbody><tr><td>Google-Konto</td><td>Für Google Cloud und die Autorisierung von Google Drive</td></tr><tr><td>Google-Cloud-Projekt</td><td>Aktiviert die Drive API und erstellt OAuth-Zugangsdaten</td></tr><tr><td>OAuth-2.0-Client</td><td>Damit ImgBed <code>Client ID</code>, <code>Client Secret</code> und <code>Refresh Token</code> erhalten kann</td></tr><tr><td>Deine ImgBed-Domain</td><td>Für die OAuth-Redirect-URI. Sie muss zur tatsächlich genutzten Domain passen.</td></tr></tbody></table><h2 id="einrichtung" tabindex="-1">Einrichtung <a class="header-anchor" href="#einrichtung" aria-label="Permalink to &quot;Einrichtung&quot;">​</a></h2><h3 id="schritt-1-google-drive-api-aktivieren" tabindex="-1">Schritt 1: Google Drive API aktivieren <a class="header-anchor" href="#schritt-1-google-drive-api-aktivieren" aria-label="Permalink to &quot;Schritt 1: Google Drive API aktivieren&quot;">​</a></h3><ol><li>Öffne die Google Cloud Console.</li><li>Erstelle ein neues Projekt oder wähle ein bestehendes aus.</li><li>Gehe zu <code>APIs &amp; Services</code>.</li><li>Klicke auf <code>Enable APIs and Services</code>.</li><li>Suche nach <code>Google Drive API</code>.</li><li>Öffne sie und aktiviere sie.</li></ol><h3 id="schritt-2-oauth-zustimmungsbildschirm-konfigurieren" tabindex="-1">Schritt 2: OAuth-Zustimmungsbildschirm konfigurieren <a class="header-anchor" href="#schritt-2-oauth-zustimmungsbildschirm-konfigurieren" aria-label="Permalink to &quot;Schritt 2: OAuth-Zustimmungsbildschirm konfigurieren&quot;">​</a></h3><ol><li>Öffne in Google Cloud die <code>Google Auth Platform</code>.</li><li>Fülle die grundlegenden Angaben unter <code>Branding</code> aus, z. B. App-Name, Support-E-Mail und Entwicklerkontakt.</li><li>Öffne <code>Audience</code>.</li><li>Für die meisten selbst betriebenen privaten Installationen passt <code>External</code>.</li><li>Wenn du <code>External</code> wählst, füge unter <code>Test users</code> das Google-Konto hinzu, das du autorisieren möchtest.</li><li>Öffne <code>Data Access</code>.</li><li>Füge die benötigten Google-Drive-Berechtigungen hinzu.</li></ol><h3 id="schritt-3-oauth-2-0-client-erstellen" tabindex="-1">Schritt 3: OAuth-2.0-Client erstellen <a class="header-anchor" href="#schritt-3-oauth-2-0-client-erstellen" aria-label="Permalink to &quot;Schritt 3: OAuth-2.0-Client erstellen&quot;">​</a></h3><ol><li>Öffne in der <code>Google Auth Platform</code> den Bereich <code>Clients</code>.</li><li>Erstelle einen neuen Client.</li><li>Setze den Anwendungstyp auf <code>Web application</code>.</li><li>Gib dem Client einen gut erkennbaren Namen.</li><li>Trage bei den autorisierten JavaScript-Ursprüngen deine ImgBed-URL ein, zum Beispiel:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Trage bei den autorisierten Redirect-URIs ein:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="OAuth-Client erstellen" loading="lazy"></p><p><img src="'+a+'" alt="Domain und Callback-URL eintragen" loading="lazy"></p><p>Nach dem Erstellen kopierst du diese Werte:</p><table tabindex="0"><thead><tr><th>Erstellter Wert</th><th>ImgBed-Feld</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="schritt-4-google-drive-kanal-ausfullen" tabindex="-1">Schritt 4: Google-Drive-Kanal ausfüllen <a class="header-anchor" href="#schritt-4-google-drive-kanal-ausfullen" aria-label="Permalink to &quot;Schritt 4: Google-Drive-Kanal ausfüllen&quot;">​</a></h2><p>Wähle in den Upload-Einstellungen <code>Google Drive</code> und fülle aus:</p><table tabindex="0"><thead><tr><th>ImgBed-Feld</th><th>Eingabe</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein gut erkennbarer Name, z. B. <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Die Client ID aus Google Cloud</td></tr><tr><td>Client Secret</td><td>Das Client Secret aus Google Cloud</td></tr><tr><td>Refresh Token</td><td>Erst einmal leer lassen. Das Token holst du im nächsten Schritt.</td></tr><tr><td>Stammverzeichnis</td><td>Optional. Standard ist <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Client-Daten in ImgBed eintragen" loading="lazy"></p><h2 id="schritt-5-refresh-token-abrufen" tabindex="-1">Schritt 5: Refresh Token abrufen <a class="header-anchor" href="#schritt-5-refresh-token-abrufen" aria-label="Permalink to &quot;Schritt 5: Refresh Token abrufen&quot;">​</a></h2><ol><li>Klicke auf <code>Get Token</code>.</li><li>Wähle das Google-Konto aus, das du verbinden möchtest.</li><li>Schließe die Autorisierung ab.</li><li>Die Callback-Seite zeigt ein <code>Refresh Token</code>.</li><li>Kopiere es.</li><li>Kehre zu ImgBed zurück und füge es in das Feld <code>Refresh Token</code> ein.</li></ol><p><img src="'+i+`" alt="Refresh Token nach Autorisierung kopieren" loading="lazy"></p><p>Wenn du später das Google-Konto wechselst, den OAuth-Client änderst oder die alte Autorisierung abläuft, musst du den Kanal nicht löschen. Öffne die Bearbeitungsseite und klicke auf <code>Reauthorize</code>.</p><h2 id="schritt-6-kanal-speichern" tabindex="-1">Schritt 6: Kanal speichern <a class="header-anchor" href="#schritt-6-kanal-speichern" aria-label="Permalink to &quot;Schritt 6: Kanal speichern&quot;">​</a></h2><p>Speichere den Kanal, sobald alle Felder ausgefüllt sind.</p><h2 id="kurzablauf" tabindex="-1">Kurzablauf <a class="header-anchor" href="#kurzablauf" aria-label="Permalink to &quot;Kurzablauf&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud öffnen</span></span>
<span class="line"><span>-&gt; Projekt erstellen oder auswählen</span></span>
<span class="line"><span>-&gt; Google Drive API aktivieren</span></span>
<span class="line"><span>-&gt; Google Auth Platform konfigurieren</span></span>
<span class="line"><span>-&gt; Bei Audience = External das eigene Google-Konto zu Test users hinzufügen</span></span>
<span class="line"><span>-&gt; OAuth-Client vom Typ Web application erstellen</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/google/callback als Redirect-URI eintragen</span></span>
<span class="line"><span>-&gt; Client ID und Client Secret in ImgBed eintragen</span></span>
<span class="line"><span>-&gt; Get Token klicken</span></span>
<span class="line"><span>-&gt; Mit Google anmelden und autorisieren</span></span>
<span class="line"><span>-&gt; Refresh Token von der Callback-Seite kopieren</span></span>
<span class="line"><span>-&gt; In ImgBed einfügen und speichern</span></span>
<span class="line"><span>-&gt; Testbild hochladen</span></span></code></pre></div><h2 id="referenzen" tabindex="-1">Referenzen <a class="header-anchor" href="#referenzen" aria-label="Permalink to &quot;Referenzen&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const v=l(d,[["render",c]]);export{k as __pageData,v as default};
